CREATE TABLE public.users (    id uuid PRIMARY KEY,    first_name varchar(100) NULL,    last_name varchar(100) NULL,    username varchar(50) NOT NULL,    "password" varchar(255) NOT NULL,    "role" varchar(20) DEFAULT 'USER'::character varying NOT NULL,    email varchar(255) NULL,    phone_number varchar(30) NULL,    email_verified bool DEFAULT false NULL,    email_verified_at timestamptz NULL,    is_active bool DEFAULT true NOT NULL,    created_at timestamptz DEFAULT now() NOT NULL,    last_login_at timestamptz NULL,    password_updated_at timestamptz NULL,    failed_login_attempts int4 DEFAULT 0 NULL,    locked_until timestamptz NULL,    deleted_at timestamptz NULL,    CONSTRAINT users_email_key UNIQUE (email),    CONSTRAINT users_username_key UNIQUE (username));---CREATE TABLE refresh_tokens (    id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),    user_id      UUID         NOT NULL REFERENCES users(id) ON DELETE CASCADE,    token_hash   VARCHAR(255) NOT NULL UNIQUE,  -- NEVER store raw token    device_hint  VARCHAR(255),    issued_at    TIMESTAMPTZ  NOT NULL DEFAULT NOW(),    expires_at   TIMESTAMPTZ  NOT NULL,    revoked_at   TIMESTAMPTZ  -- NULL = still valid);CREATE INDEX idx_refresh_tokens_user ON refresh_tokens(user_id);---CREATE TABLE upload_sessions (    id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),    user_id          UUID         NOT NULL REFERENCES users(id),    filename         VARCHAR(512) NOT NULL,    total_size       BIGINT       NOT NULL,    chunk_size       INT          NOT NULL,    total_chunks     INT          NOT NULL,    received_chunks  INT[]        NOT NULL DEFAULT '{}',  -- PostgreSQL array    destination_path TEXT         NOT NULL,    status           VARCHAR(20)  NOT NULL DEFAULT 'PENDING',    created_at       TIMESTAMPTZ  NOT NULL DEFAULT NOW(),    expires_at       TIMESTAMPTZ  NOT NULL DEFAULT NOW() + INTERVAL '48 hours');---CREATE TABLE transfer_log (    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),    user_id       UUID         REFERENCES users(id),    filename      VARCHAR(512) NOT NULL,    source        VARCHAR(512),    destination   VARCHAR(512),    size_bytes    BIGINT,    avg_speed_bps BIGINT,    duration_ms   BIGINT,    status        VARCHAR(20)  NOT NULL DEFAULT 'PENDING',    error_message TEXT,    created_at    TIMESTAMPTZ  NOT NULL DEFAULT NOW());CREATE INDEX idx_transfer_log_user ON transfer_log(user_id, created_at DESC);---CREATE TABLE otp_tokens (    id         UUID PRIMARY KEY DEFAULT gen_random_uuid(),    user_id    UUID        NOT NULL REFERENCES users(id),    token_hash VARCHAR(255) NOT NULL,    purpose    VARCHAR(30)  NOT NULL,  -- 'RESET' or 'PAIR'    expires_at TIMESTAMPTZ  NOT NULL,    used_at    TIMESTAMPTZ  -- NULL = not yet used);